#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main(int argc, char **argv) {
    printf("argc = %d\n", argc);
    if (argc > 1) printf("argv[1] length = %zu\n", strlen(argv[1]));
    if (argc > 2) printf("argv[2] length = %zu\n", strlen(argv[2]));

    // Show the issue
    char buf[256];
    printf("buf size = %zu\n", sizeof(buf));
    printf("Attempting to copy %zu bytes into %zu byte buffer\n", 
           argc > 1 ? strlen(argv[1]) + 1 : 0, sizeof(buf));

    return 0;
}
EOF
